import { createSupabaseClient, initializeSupabase } from '@/lib'

// Option 1: Explicit configuration
const client = createSupabaseClient({
  url: process.env.VITE_SUPABASE_URL!,
  anonKey: process.env.VITE_SUPABASE_ANON_KEY!,
})

// Option 2: Auto-initialize from environment
const client = initializeSupabase()

// Option 3: Lazy retrieval (auto-initializes)
const { getSupabaseClient } = '@/lib'
const client = getSupabaseClient()

// Application Layer → QueryEngine → Database → Cache → Supabase Client
import { queryEngine } from '@/lib'

// QueryEngine handles caching and deduplication automatically
const users = await queryEngine.query({
  table: 'users',
  filters: [{ column: 'status', operator: 'eq', value: 'active' }],
})
// Flow: check cache → if miss, build query → apply filters → execute with retry → cache result → return
